import{_ as n,c as a,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"Anhang | agent-app-factory","description":"Referenzdokumentation: Vollständige Liste der CLI-Befehle, detaillierte Erklärung der Projektverzeichnisstruktur, Code-Standard-Anforderungen und Technologie-Stack-Beschreibung.","frontmatter":{"title":"Anhang | agent-app-factory","sidebarTitle":"Anhang","subtitle":"Anhang","description":"Referenzdokumentation: Vollständige Liste der CLI-Befehle, detaillierte Erklärung der Projektverzeichnisstruktur, Code-Standard-Anforderungen und Technologie-Stack-Beschreibung.","order":210},"headers":[],"relativePath":"de/hyz1992/agent-app-factory/appendix/index.md","filePath":"de/hyz1992/agent-app-factory/appendix/index.md"}'),r={name:"de/hyz1992/agent-app-factory/appendix/index.md"};function d(s,e,o,l,h,c){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="anhang" tabindex="-1">Anhang <a class="header-anchor" href="#anhang" aria-label="Permalink to &quot;Anhang&quot;">​</a></h1><p>Dieses Kapitel enthält Referenzdokumentation und ergänzende Materialien, die dir helfen, die technischen Details der AI App Factory tiefer zu verstehen.</p><h2 id="unterseiten-navigation" tabindex="-1">Unterseiten-Navigation <a class="header-anchor" href="#unterseiten-navigation" aria-label="Permalink to &quot;Unterseiten-Navigation&quot;">​</a></h2><h3 id="cli-befehlsreferenz" tabindex="-1"><a href="./../cli-commands/">CLI-Befehlsreferenz</a> <a class="header-anchor" href="#cli-befehlsreferenz" aria-label="Permalink to &quot;[CLI-Befehlsreferenz](../cli-commands/)&quot;">​</a></h3><p>Vollständige Liste der CLI-Befehle, Parameterbeschreibungen und Verwendungsbeispiele, einschließlich der Befehle <code>init</code>, <code>run</code>, <code>continue</code>, <code>status</code>, <code>list</code> und <code>reset</code>.</p><h3 id="verzeichnisstruktur-im-detail" tabindex="-1"><a href="./../directory-structure/">Verzeichnisstruktur im Detail</a> <a class="header-anchor" href="#verzeichnisstruktur-im-detail" aria-label="Permalink to &quot;[Verzeichnisstruktur im Detail](../directory-structure/)&quot;">​</a></h3><p>Erfahre mehr über die vollständige Verzeichnisstruktur des Factory-Projekts und die Zwecke der einzelnen Dateien, einschließlich der Funktionen der Kernverzeichnisse wie <code>agents/</code>, <code>skills/</code> und <code>cli/</code>.</p><h3 id="code-standards" tabindex="-1"><a href="./../code-standards/">Code-Standards</a> <a class="header-anchor" href="#code-standards" aria-label="Permalink to &quot;[Code-Standards](../code-standards/)&quot;">​</a></h3><p>Erfahre mehr über die TypeScript-Codierungsstandards, die für den generierten Code gelten, die Dateistruktur, Anforderungen an Kommentare und Konventionen für Commit-Nachrichten.</p><h3 id="technologie-stack-im-detail" tabindex="-1"><a href="./../tech-stack/">Technologie-Stack im Detail</a> <a class="header-anchor" href="#technologie-stack-im-detail" aria-label="Permalink to &quot;[Technologie-Stack im Detail](../tech-stack/)&quot;">​</a></h3><p>Erfahre mehr über den Technologie-Stack der generierten Anwendung: Node.js + Express + Prisma + React Native sowie die Gründe für die jeweiligen Technologie-Entscheidungen.</p><h2 id="lernpfad-empfehlungen" tabindex="-1">Lernpfad-Empfehlungen <a class="header-anchor" href="#lernpfad-empfehlungen" aria-label="Permalink to &quot;Lernpfad-Empfehlungen&quot;">​</a></h2><p>Die Dokumentation in diesem Kapitel ist <strong>Referenzmaterial</strong> und muss nicht in einer bestimmten Reihenfolge gelesen werden. Es wird empfohlen, die entsprechenden Abschnitte bei Bedarf während des Lernens des Haupttutorials zu konsultieren:</p><ul><li>Beim Lernen von <a href="./../../start/installation/">Installation und Konfiguration</a> kannst du die <a href="./../cli-commands/">CLI-Befehlsreferenz</a> konsultieren</li><li>Beim Lernen von <a href="./../../start/init-project/">Factory-Projekt initialisieren</a> kannst du die <a href="./../directory-structure/">Verzeichnisstruktur im Detail</a> konsultieren</li><li>Beim Lernen der verschiedenen Phasen der Pipeline kannst du den <a href="./../tech-stack/">Technologie-Stack im Detail</a> konsultieren</li><li>Wenn du die Qualitätsstandards des generierten Codes verstehen musst, kannst du die <a href="./../code-standards/">Code-Standards</a> konsultieren</li></ul><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><p>Keine Voraussetzungen erforderlich. Um den Inhalt dieses Kapitels jedoch besser zu verstehen, wird empfohlen, die folgenden Tutorials zuerst abzuschließen:</p><ul><li>✅ <a href="./../../start/getting-started/">Schnellstart: Von der Idee zur App</a></li><li>✅ <a href="./../../start/installation/">Installation und Konfiguration</a></li><li>✅ <a href="./../../start/init-project/">Factory-Projekt initialisieren</a></li></ul><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss des Haupttutorials kannst du Folgendes erkunden:</p><ul><li>Sieh dir die <a href="./../../changelog/release-notes/">Versionshinweise</a> an, um die neuesten Funktionen kennenzulernen</li><li>Überprüfe die <a href="./../../faq/best-practices/">Best Practices</a>, um die Effizienz zu steigern</li><li>Vertiefe dich in <a href="./../../advanced/">Erweiterte Themen</a>, um die Systemdesign-Prinzipien zu verstehen</li></ul>',20)])])}const p=n(r,[["render",d]]);export{f as __pageData,p as default};
